     3→import { ArrowLeft, ArrowRight, ShoppingCart } from "lucide-react";
     4→import Link from "next/link";
     5→import { useRouter } from "next/navigation";
     6→import { useCallback, useState } from "react";
     7→import { CheckoutLoginGate } from "@/components/storefront/checkout-login-gate";
     8→import { CouponInput } from "@/components/storefront/coupon-input";
     9→import { OrderSidebar } from "@/components/storefront/order-sidebar";
    10→import { PaymentSection } from "@/components/storefront/payment-section";
    11→import { ShippingSection } from "@/components/storefront/shipping-section";
    12→import { StepIndicator } from "@/components/storefront/step-indicator";
    13→import { Button } from "@/components/ui/button";
    14→import { Skeleton } from "@/components/ui/skeleton";
    15→import { useCart } from "@/hooks/use-cart";
    16→import type { ShippingAddressDto } from "@/lib/api";
    17→
    18→const CHECKOUT_STEPS = [
    19→  { label: "Shipping" },
    20→  { label: "Payment" },
    21→  { label: "Review" },
    22→];
    23→
    24→export function CheckoutPage() {
    25→  const router = useRouter();
    26→  const { data: cart, isLoading } = useCart();
    27→
    28→  const [checkoutStarted, setCheckoutStarted] = useState(false);
    29→  const [currentStep, setCurrentStep] = useState(1);
    30→  const [shippingData, setShippingData] = useState<ShippingAddressDto | null>(
    31→    null,
    32→  );
    33→  const [appliedCoupon, setAppliedCoupon] = useState<string | null>(null);
    34→  const [discountAmount, setDiscountAmount] = useState(0);
    35→
    36→  const handleContinueAsGuest = useCallback(() => {
    37→    setCheckoutStarted(true);
    38→  }, []);
    39→
    40→  function handleShippingComplete(data: ShippingAddressDto) {
    41→    setShippingData(data);
    42→    setCurrentStep(2);
    43→  }
    44→
    45→  function handlePaymentSuccess(orderId: string) {
    46→    router.push(`/order-confirmation/${orderId}`);
    47→  }
    48→
    49→  function handleBack() {
    50→    if (currentStep > 1) {
    51→      setCurrentStep(currentStep - 1);
    52→    }
    53→  }
    54→
    55→  if (isLoading) {
    56→    return <CheckoutSkeleton />;
    57→  }
    58→
    59→  const items = cart?.items ?? [];
    60→
    61→  if (items.length === 0) {
    62→    return (
    63→      <div className="mx-auto max-w-7xl px-4 py-16">
    64→        <div className="flex flex-col items-center justify-center py-24 text-center">
    65→          <ShoppingCart className="mb-4 size-12 text-muted-foreground" />
    66→          <h2 className="text-xl font-semibold text-foreground">
    67→            Your cart is empty
    68→          </h2>
    69→          <p className="mt-2 text-sm text-muted-foreground">
    70→            Add some items to your cart before checking out.
    71→          </p>
    72→          <Button asChild className="mt-6" size="lg">
    73→            <Link href="/">Continue shopping</Link>
    74→          </Button>
    75→        </div>
    76→      </div>
    77→    );
    78→  }
    79→
    80→  if (!checkoutStarted) {
    81→    return (
    82→      <div className="mx-auto max-w-7xl px-4 py-8">
    83→        <h1 className="mb-8 text-2xl font-bold tracking-tight text-foreground">
    84→          Checkout
    85→        </h1>
    86→        <CheckoutLoginGate onContinueAsGuest={handleContinueAsGuest} />
    87→      </div>
    88→    );
    89→  }
    90→
    91→  return (
    92→    <div className="mx-auto max-w-7xl px-4 py-8">
    93→      <h1 className="mb-6 text-2xl font-bold tracking-tight text-foreground">
    94→        Checkout
    95→      </h1>
    96→
    97→      {/* Step Indicator */}
    98→      <div className="mb-8">
    99→        <StepIndicator steps={CHECKOUT_STEPS} currentStep={currentStep} />
   100→      </div>
   101→
   102→      {/* Two-column layout: form + sidebar */}
   103→      <div className="grid grid-cols-1 gap-8 lg:grid-cols-3">
   104→        {/* Left column: step content */}
   105→        <div className="lg:col-span-2">
   106→          {/* Step 1: Shipping */}
   107→          {currentStep === 1 && (
   108→            <div className="space-y-4">
   109→              <div className="rounded-lg border bg-card p-6">
   110→                <h2 className="mb-5 text-lg font-bold text-foreground">
   111→                  Shipping Address
   112→                </h2>
   113→                <ShippingSection onComplete={handleShippingComplete} />
   114→              </div>
   115→              <div className="rounded-lg border bg-card p-6">
   116→                <h2 className="mb-3 text-base font-semibold text-foreground">
   117→                  Promo Code
   118→                </h2>
   119→                <CouponInput
   120→                  subtotal={items.reduce((s, i) => s + i.lineTotal, 0)}
   121→                  onApply={(code, amount) => {
   122→                    setAppliedCoupon(code);
   123→                    setDiscountAmount(amount);
   124→                  }}
   125→                  onRemove={() => {
   126→                    setAppliedCoupon(null);
   127→                    setDiscountAmount(0);
   128→                  }}
   129→                  appliedCode={appliedCoupon}
   130→                  discountAmount={discountAmount}
   131→                />
   132→              </div>
   133→            </div>
   134→          )}
   135→
   136→          {/* Step 2: Payment */}
   137→          {currentStep === 2 && shippingData && (
   138→            <div className="rounded-lg border bg-card p-6">
   139→              <h2 className="mb-5 text-lg font-bold text-foreground">
   140→                Payment
   141→              </h2>
   142→              <PaymentSection
   143→                shippingData={shippingData}
   144→                couponCode={appliedCoupon ?? undefined}
   145→                onSuccess={handlePaymentSuccess}
   146→              />
   147→            </div>
   148→          )}
   149→
   150→          {/* Step 3: Review */}
   151→          {currentStep === 3 && shippingData && (
   152→            <div className="rounded-lg border bg-card p-6">
   153→              <h2 className="mb-5 text-lg font-bold text-foreground">
   154→                Review Order
   155→              </h2>
   156→              <div className="space-y-4">
   157→                <div className="rounded-md border bg-background p-4">
   158→                  <p className="mb-1 text-sm font-medium text-foreground">
   159→                    Shipping to
   160→                  </p>
   161→                  <p className="text-sm text-muted-foreground">
   162→                    {shippingData.name}
   163→                  </p>
   164→                  <p className="text-sm text-muted-foreground">
   165→                    {shippingData.street}
   166→                  </p>
   167→                  <p className="text-sm text-muted-foreground">
   168→                    {shippingData.city}, {shippingData.state}{" "}
   169→                    {shippingData.zipCode}
   170→                  </p>
   171→                </div>
   172→                <PaymentSection
   173→                  shippingData={shippingData}
   174→                  couponCode={appliedCoupon ?? undefined}
   175→                  onSuccess={handlePaymentSuccess}
   176→                />
   177→              </div>
   178→            </div>
   179→          )}
   180→
   181→          {/* Navigation buttons */}
   182→          <div className="mt-6 flex justify-end gap-3">
   183→            {currentStep > 1 && (
   184→              <Button variant="outline" onClick={handleBack}>
   185→                <ArrowLeft className="mr-2 size-4" />
   186→                Back
   187→              </Button>
   188→            )}
   189→            {currentStep === 1 && (
   190→              <Button variant="outline" asChild>
   191→                <Link href="/cart">
   192→                  <ArrowLeft className="mr-2 size-4" />
   193→                  Back to Cart
   194→                </Link>
   195→              </Button>
   196→            )}
   197→            {currentStep === 1 && (
   198→              <Button
   199→                type="submit"
   200→                form="shipping-form"
   201→                aria-label="Continue to Payment"
   202→              >
   203→                Continue to Payment
   204→                <ArrowRight className="ml-2 size-4" />
   205→              </Button>
   206→            )}
   207→          </div>
   208→        </div>
   209→
   210→        {/* Right column: order summary sidebar */}
