   212→          <OrderSidebar
   213→            couponCode={appliedCoupon}
   214→            discountAmount={discountAmount}
   215→          />
   216→        </div>
   217→      </div>
   218→    </div>
   219→  );
   220→}
   221→
   222→function CheckoutSkeleton() {
   223→  return (
   224→    <div className="mx-auto max-w-7xl px-4 py-8">
