"use client";

import { ArrowLeft, ArrowRight, ShoppingCart } from "lucide-react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useCallback, useState } from "react";
import { CheckoutLoginGate } from "@/components/storefront/checkout-login-gate";
import { CouponInput } from "@/components/storefront/coupon-input";
import { OrderSidebar } from "@/components/storefront/order-sidebar";
import { PaymentSection } from "@/components/storefront/payment-section";
import { ShippingSection } from "@/components/storefront/shipping-section";
import { StepIndicator } from "@/components/storefront/step-indicator";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { useCart } from "@/hooks/use-cart";
import type { ShippingAddressDto } from "@/lib/api";

const CHECKOUT_STEPS = [
  { label: "Shipping" },
  { label: "Payment" },
  { label: "Review" },
];

export function CheckoutPage() {
  const router = useRouter();
  const { data: cart, isLoading } = useCart();

  const [checkoutStarted, setCheckoutStarted] = useState(false);
  const [currentStep, setCurrentStep] = useState(1);
  const [shippingData, setShippingData] = useState<ShippingAddressDto | null>(
    null,
  );
  const [appliedCoupon, setAppliedCoupon] = useState<string | null>(null);
  const [discountAmount, setDiscountAmount] = useState(0);

  const handleContinueAsGuest = useCallback(() => {
    setCheckoutStarted(true);
  }, []);

  function handleShippingComplete(data: ShippingAddressDto) {
    setShippingData(data);
    setCurrentStep(2);
  }

  function handlePaymentSuccess(orderId: string) {
    router.push(`/order-confirmation/${orderId}`);
  }

  function handleBack() {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      if (currentStep === 2) {
        setAppliedCoupon(null);
        setDiscountAmount(0);
      }
    }
  }

  if (isLoading) {
    return <CheckoutSkeleton />;
  }

  const items = cart?.items ?? [];

  if (items.length === 0) {
    return (
      <div className="mx-auto max-w-7xl px-4 py-16">
        <div className="flex flex-col items-center justify-center py-24 text-center">
          <ShoppingCart className="mb-4 size-12 text-muted-foreground" />
          <h2 className="text-xl font-semibold text-foreground">
            Your cart is empty
          </h2>
          <p className="mt-2 text-sm text-muted-foreground">
            Add some items to your cart before checking out.
          </p>
          <Button asChild className="mt-6" size="lg">
            <Link href="/">Continue shopping</Link>
          </Button>
        </div>
      </div>
    );
  }

  if (!checkoutStarted) {
    return (
      <div className="mx-auto max-w-7xl px-4 py-8">
        <h1 className="mb-8 text-2xl font-bold tracking-tight text-foreground">
          Checkout
        </h1>
        <CheckoutLoginGate onContinueAsGuest={handleContinueAsGuest} />
      </div>
    );
  }

  return (
    <div className="mx-auto max-w-7xl px-4 py-8">
      <h1 className="mb-6 text-2xl font-bold tracking-tight text-foreground">
        Checkout
      </h1>

      {/* Step Indicator */}
      <div className="mb-8">
        <StepIndicator steps={CHECKOUT_STEPS} currentStep={currentStep} />
      </div>

      {/* Two-column layout: form + sidebar */}
      <div className="grid grid-cols-1 gap-8 lg:grid-cols-3">
        {/* Left column: step content */}
        <div className="lg:col-span-2">
          {/* Step 1: Shipping */}
          {currentStep === 1 && (
            <div className="space-y-4">
              <div className="rounded-lg border bg-card p-6">
                <h2 className="mb-5 text-lg font-bold text-foreground">
                  Shipping Address
                </h2>
                <ShippingSection onComplete={handleShippingComplete} />
              </div>
              <div className="rounded-lg border bg-card p-6">
                <h2 className="mb-3 text-base font-semibold text-foreground">
                  Promo Code
                </h2>
                <CouponInput
                  subtotal={items.reduce((s, i) => s + i.lineTotal, 0)}
                  onApply={(code, amount) => {
                    setAppliedCoupon(code);
                    setDiscountAmount(amount);
                  }}
                  onRemove={() => {
                    setAppliedCoupon(null);
                    setDiscountAmount(0);
                  }}
                  appliedCode={appliedCoupon}
                  discountAmount={discountAmount}
                />
              </div>
            </div>
          )}

          {/* Step 2: Payment */}
          {currentStep === 2 && shippingData && (
            <div className="rounded-lg border bg-card p-6">
              <h2 className="mb-5 text-lg font-bold text-foreground">
                Payment
              </h2>
              <PaymentSection
                shippingData={shippingData}
                couponCode={appliedCoupon ?? undefined}
                onSuccess={handlePaymentSuccess}
              />
            </div>
          )}

          {/* Step 3: Review */}
          {currentStep === 3 && shippingData && (
            <div className="rounded-lg border bg-card p-6">
              <h2 className="mb-5 text-lg font-bold text-foreground">
                Review Order
              </h2>
              <div className="space-y-4">
                <div className="rounded-md border bg-background p-4">
                  <p className="mb-1 text-sm font-medium text-foreground">
                    Shipping to
                  </p>
                  <p className="text-sm text-muted-foreground">
                    {shippingData.name}
                  </p>
                  <p className="text-sm text-muted-foreground">
                    {shippingData.street}
                  </p>
                  <p className="text-sm text-muted-foreground">
                    {shippingData.city}, {shippingData.state}{" "}
                    {shippingData.zipCode}
                  </p>
                </div>
                <PaymentSection
                  shippingData={shippingData}
                  couponCode={appliedCoupon ?? undefined}
                  onSuccess={handlePaymentSuccess}
                />
              </div>
            </div>
          )}

          {/* Navigation buttons */}
          <div className="mt-6 flex justify-end gap-3">
            {currentStep > 1 && (
              <Button variant="outline" onClick={handleBack}>
                <ArrowLeft className="mr-2 size-4" />
                Back
              </Button>
            )}
            {currentStep === 1 && (
              <Button variant="outline" asChild>
                <Link href="/cart">
                  <ArrowLeft className="mr-2 size-4" />
                  Back to Cart
                </Link>
              </Button>
            )}
            {currentStep === 1 && (
              <Button
                type="submit"
                form="shipping-form"
                aria-label="Continue to Payment"
              >
                Continue to Payment
                <ArrowRight className="ml-2 size-4" />
              </Button>
            )}
          </div>
        </div>

        {/* Right column: order summary sidebar */}
        <div>
          <OrderSidebar
            couponCode={appliedCoupon}
            discountAmount={discountAmount}
          />
        </div>
      </div>
    </div>
  );
}

function CheckoutSkeleton() {
  return (
    <div className="mx-auto max-w-7xl px-4 py-8">
      <Skeleton className="mb-6 h-8 w-32" />
      <Skeleton className="mb-8 h-10 w-full max-w-lg" />
      <div className="grid grid-cols-1 gap-8 lg:grid-cols-3">
        <div className="space-y-4 lg:col-span-2">
          <Skeleton className="h-64 rounded-lg" />
          <Skeleton className="h-16 rounded-lg" />
        </div>
        <div>
          <Skeleton className="h-80 rounded-lg" />
        </div>
      </div>
    </div>
  );
}

"use client";

import { Loader2 } from "lucide-react";
import { useEffect, useState } from "react";

import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { useCreateCoupon, useUpdateCoupon } from "@/hooks/use-coupons";
import type { CouponDto } from "@/lib/api";

interface CouponDialogProps {
  open: boolean;
  onClose: () => void;
  coupon: CouponDto | null;
}

interface FormData {
  code: string;
  description: string;
  discountType: string;
  discountValue: string;
  validFrom: string;
  validUntil: string;
  minOrderAmount: string;
  maxDiscountAmount: string;
  usageLimit: string;
  usagePerUser: string;
}

function toDateInputValue(iso: string | null | undefined): string {
  if (!iso) return "";
  return iso.slice(0, 10);
}

const EMPTY_FORM: FormData = {
  code: "",
  description: "",
  discountType: "Percentage",
  discountValue: "",
  validFrom: new Date().toISOString().slice(0, 10),
  validUntil: "",
  minOrderAmount: "",
  maxDiscountAmount: "",
  usageLimit: "",
  usagePerUser: "",
};

export function CouponDialog({ open, onClose, coupon }: CouponDialogProps) {
  const isEditing = !!coupon;
  const createCoupon = useCreateCoupon();
  const updateCoupon = useUpdateCoupon();
  const isPending = createCoupon.isPending || updateCoupon.isPending;

  const [formData, setFormData] = useState<FormData>(EMPTY_FORM);
  const [errors, setErrors] = useState<Partial<FormData>>({});

  useEffect(() => {
    if (open) {
      if (coupon) {
        setFormData({
          code: coupon.code,
          description: coupon.description,
          discountType: coupon.discountType,
          discountValue: coupon.discountValue.toString(),
          validFrom: toDateInputValue(coupon.validFrom),
          validUntil: toDateInputValue(coupon.validUntil),
          minOrderAmount: coupon.minOrderAmount?.toString() ?? "",
          maxDiscountAmount: coupon.maxDiscountAmount?.toString() ?? "",
          usageLimit: coupon.usageLimit?.toString() ?? "",
          usagePerUser: coupon.usagePerUser?.toString() ?? "",
        });
      } else {
        setFormData(EMPTY_FORM);
      }
      setErrors({});
    }
  }, [open, coupon]);

  function validate(): boolean {
    const newErrors: Partial<FormData> = {};
    if (!formData.code.trim()) newErrors.code = "Code is required";
    if (!formData.description.trim())
      newErrors.description = "Description is required";
    if (!formData.discountValue || Number(formData.discountValue) <= 0)
      newErrors.discountValue = "Discount value must be greater than 0";
    if (
      formData.discountType === "Percentage" &&
      Number(formData.discountValue) > 100
    )
      newErrors.discountValue = "Percentage cannot exceed 100";
    if (!formData.validFrom)
      newErrors.validFrom = "Valid from date is required";
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }

  function field(key: keyof FormData) {
    return {
      value: formData[key],
      onChange: (
        e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>,
      ) => {
        setFormData((prev) => ({ ...prev, [key]: e.target.value }));
        if (errors[key]) setErrors((prev) => ({ ...prev, [key]: undefined }));
      },
    };
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!validate()) return;

    const payload = {
      description: formData.description.trim(),
      discountType: formData.discountType,
      discountValue: Number(formData.discountValue),
      validFrom: new Date(formData.validFrom).toISOString(),
      validUntil: formData.validUntil
        ? new Date(formData.validUntil).toISOString()
        : undefined,
      minOrderAmount: formData.minOrderAmount
        ? Number(formData.minOrderAmount)
        : undefined,
      maxDiscountAmount: formData.maxDiscountAmount
        ? Number(formData.maxDiscountAmount)
        : undefined,
      usageLimit: formData.usageLimit ? Number(formData.usageLimit) : undefined,
      usagePerUser: formData.usagePerUser
        ? Number(formData.usagePerUser)
        : undefined,
    };

    if (isEditing && coupon) {
      updateCoupon.mutate(
        { id: coupon.id, data: payload },
        { onSuccess: onClose },
      );
    } else {
      createCoupon.mutate(
        { ...payload, code: formData.code.trim().toUpperCase() },
        { onSuccess: onClose },
      );
    }
  }

  return (
    <Dialog open={open} onOpenChange={(isOpen) => !isOpen && onClose()}>
      <DialogContent className="sm:max-w-[560px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>
            {isEditing ? "Edit Coupon" : "Create Coupon"}
          </DialogTitle>
          <DialogDescription>
            {isEditing
              ? "Update the coupon details below."
              : "Create a new discount coupon."}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit}>
          <div className="grid gap-4 py-4">
            {/* Code — only on create */}
            {!isEditing && (
              <div className="space-y-1.5">
                <Label htmlFor="code">Code *</Label>
                <Input
                  id="code"
                  placeholder="SUMMER20"
                  disabled={isPending}
                  className={errors.code ? "border-destructive" : ""}
                  {...field("code")}
                  onChange={(e) => {
                    setFormData((prev) => ({
                      ...prev,
                      code: e.target.value.toUpperCase(),
                    }));
                    if (errors.code)
                      setErrors((prev) => ({ ...prev, code: undefined }));
                  }}
                />
                {errors.code && (
                  <p className="text-sm text-destructive">{errors.code}</p>
                )}
              </div>
            )}

            {/* Description */}
            <div className="space-y-1.5">
              <Label htmlFor="description">Description *</Label>
              <Textarea
                id="description"
                placeholder="Short description of this coupon"
                rows={2}
                disabled={isPending}
                className={errors.description ? "border-destructive" : ""}
                {...field("description")}
              />
              {errors.description && (
                <p className="text-sm text-destructive">{errors.description}</p>
              )}
            </div>

            {/* Discount Type + Value */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label>Discount Type *</Label>
                <Select
                  value={formData.discountType}
                  onValueChange={(v) =>
                    setFormData((prev) => ({ ...prev, discountType: v }))
                  }
                  disabled={isPending}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Percentage">Percentage (%)</SelectItem>
                    <SelectItem value="FixedAmount">
                      Fixed Amount ($)
                    </SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="discountValue">
                  Value {formData.discountType === "Percentage" ? "(%)" : "($)"}{" "}
                  *
                </Label>
                <Input
                  id="discountValue"
                  type="number"
                  min="0"
                  step="0.01"
                  placeholder={
                    formData.discountType === "Percentage" ? "20" : "10.00"
                  }
                  disabled={isPending}
                  className={errors.discountValue ? "border-destructive" : ""}
                  {...field("discountValue")}
                />
                {errors.discountValue && (
                  <p className="text-sm text-destructive">
                    {errors.discountValue}
                  </p>
                )}
              </div>
            </div>

            {/* Valid From + Valid Until */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label htmlFor="validFrom">Valid From *</Label>
                <Input
                  id="validFrom"
                  type="date"
                  disabled={isPending}
                  className={errors.validFrom ? "border-destructive" : ""}
                  {...field("validFrom")}
                />
                {errors.validFrom && (
                  <p className="text-sm text-destructive">{errors.validFrom}</p>
                )}
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="validUntil">Valid Until</Label>
                <Input
                  id="validUntil"
                  type="date"
                  disabled={isPending}
                  {...field("validUntil")}
                />
              </div>
            </div>

            {/* Optional constraints */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label htmlFor="minOrderAmount">Min Order Amount ($)</Label>
                <Input
                  id="minOrderAmount"
                  type="number"
                  min="0"
                  step="0.01"
                  placeholder="50.00"
                  disabled={isPending}
                  {...field("minOrderAmount")}
                />
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="maxDiscountAmount">Max Discount ($)</Label>
                <Input
                  id="maxDiscountAmount"
                  type="number"
                  min="0"
                  step="0.01"
                  placeholder="100.00"
                  disabled={isPending}
                  {...field("maxDiscountAmount")}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label htmlFor="usageLimit">Total Usage Limit</Label>
                <Input
                  id="usageLimit"
                  type="number"
                  min="1"
                  placeholder="100"
                  disabled={isPending}
                  {...field("usageLimit")}
                />
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="usagePerUser">Per-User Limit</Label>
                <Input
                  id="usagePerUser"
                  type="number"
                  min="1"
                  placeholder="1"
                  disabled={isPending}
                  {...field("usagePerUser")}
                />
              </div>
            </div>
          </div>

          <DialogFooter>
            <Button
              type="button"
              variant="outline"
              onClick={onClose}
              disabled={isPending}
            >
              Cancel
            </Button>
            <Button type="submit" disabled={isPending}>
              {isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {isEditing ? "Update" : "Create"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { Loader2 } from "lucide-react";
import { useEffect, useState } from "react";

import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { useCreateCoupon, useUpdateCoupon } from "@/hooks/use-coupons";
import type { CouponDto } from "@/lib/api";

interface CouponDialogProps {
  open: boolean;
  onClose: () => void;
  coupon: CouponDto | null;
}

interface FormData {
  code: string;
  description: string;
  discountType: string;
  discountValue: string;
  validFrom: string;
  validUntil: string;
  minOrderAmount: string;
  maxDiscountAmount: string;
  usageLimit: string;
  usagePerUser: string;
}

function toDateInputValue(iso: string | null | undefined): string {
  if (!iso) return "";
  return iso.slice(0, 10);
}

const EMPTY_FORM: FormData = {
  code: "",
  description: "",
  discountType: "Percentage",
  discountValue: "",
  validFrom: new Date().toISOString().slice(0, 10),
  validUntil: "",
  minOrderAmount: "",
  maxDiscountAmount: "",
  usageLimit: "",
  usagePerUser: "",
};

export function CouponDialog({ open, onClose, coupon }: CouponDialogProps) {
  const isEditing = !!coupon;
  const createCoupon = useCreateCoupon();
  const updateCoupon = useUpdateCoupon();
  const isPending = createCoupon.isPending || updateCoupon.isPending;

  const [formData, setFormData] = useState<FormData>(EMPTY_FORM);
  const [errors, setErrors] = useState<Partial<FormData>>({});

  useEffect(() => {
    if (open) {
      if (coupon) {
        setFormData({
          code: coupon.code,
          description: coupon.description,
          discountType: coupon.discountType,
          discountValue: coupon.discountValue.toString(),
          validFrom: toDateInputValue(coupon.validFrom),
          validUntil: toDateInputValue(coupon.validUntil),
          minOrderAmount: coupon.minOrderAmount?.toString() ?? "",
          maxDiscountAmount: coupon.maxDiscountAmount?.toString() ?? "",
          usageLimit: coupon.usageLimit?.toString() ?? "",
          usagePerUser: coupon.usagePerUser?.toString() ?? "",
        });
      } else {
        setFormData(EMPTY_FORM);
      }
      setErrors({});
    }
  }, [open, coupon]);

  function validate(): boolean {
    const newErrors: Partial<FormData> = {};
    if (!formData.code.trim()) newErrors.code = "Code is required";
    if (!formData.description.trim())
      newErrors.description = "Description is required";
    if (!formData.discountValue || Number(formData.discountValue) <= 0)
      newErrors.discountValue = "Discount value must be greater than 0";
    if (
      formData.discountType === "Percentage" &&
      Number(formData.discountValue) > 100
    )
      newErrors.discountValue = "Percentage cannot exceed 100";
    if (!formData.validFrom)
      newErrors.validFrom = "Valid from date is required";
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }

  function field(key: keyof FormData) {
    return {
      value: formData[key],
      onChange: (
        e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>,
      ) => {
        setFormData((prev) => ({ ...prev, [key]: e.target.value }));
        if (errors[key]) setErrors((prev) => ({ ...prev, [key]: undefined }));
      },
    };
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!validate()) return;

    const payload = {
      description: formData.description.trim(),
      discountType: formData.discountType,
      discountValue: Number(formData.discountValue),
      validFrom: new Date(formData.validFrom).toISOString(),
      validUntil: formData.validUntil
        ? `${formData.validUntil}T23:59:59`
        : undefined,
      minOrderAmount: formData.minOrderAmount
        ? Number(formData.minOrderAmount)
        : undefined,
      maxDiscountAmount: formData.maxDiscountAmount
        ? Number(formData.maxDiscountAmount)
        : undefined,
      usageLimit: formData.usageLimit ? Number(formData.usageLimit) : undefined,
      usagePerUser: formData.usagePerUser
        ? Number(formData.usagePerUser)
        : undefined,
    };

    if (isEditing && coupon) {
      updateCoupon.mutate(
        { id: coupon.id, data: payload },
        { onSuccess: onClose },
      );
    } else {
      createCoupon.mutate(
        { ...payload, code: formData.code.trim().toUpperCase() },
        { onSuccess: onClose },
      );
    }
  }

  return (
    <Dialog open={open} onOpenChange={(isOpen) => !isOpen && onClose()}>
      <DialogContent className="sm:max-w-[560px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>
            {isEditing ? "Edit Coupon" : "Create Coupon"}
          </DialogTitle>
          <DialogDescription>
            {isEditing
              ? "Update the coupon details below."
              : "Create a new discount coupon."}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit}>
          <div className="grid gap-4 py-4">
            {/* Code — only on create */}
            {!isEditing && (
              <div className="space-y-1.5">
                <Label htmlFor="code">Code *</Label>
                <Input
                  id="code"
                  placeholder="SUMMER20"
                  disabled={isPending}
                  className={errors.code ? "border-destructive" : ""}
                  {...field("code")}
                  onChange={(e) => {
                    setFormData((prev) => ({
                      ...prev,
                      code: e.target.value.toUpperCase(),
                    }));
                    if (errors.code)
                      setErrors((prev) => ({ ...prev, code: undefined }));
                  }}
                />
                {errors.code && (
                  <p className="text-sm text-destructive">{errors.code}</p>
                )}
              </div>
            )}

            {/* Description */}
            <div className="space-y-1.5">
              <Label htmlFor="description">Description *</Label>
              <Textarea
                id="description"
                placeholder="Short description of this coupon"
                rows={2}
                disabled={isPending}
                className={errors.description ? "border-destructive" : ""}
                {...field("description")}
              />
              {errors.description && (
                <p className="text-sm text-destructive">{errors.description}</p>
              )}
            </div>

            {/* Discount Type + Value */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label>Discount Type *</Label>
                <Select
                  value={formData.discountType}
                  onValueChange={(v) =>
                    setFormData((prev) => ({ ...prev, discountType: v }))
                  }
                  disabled={isPending}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Percentage">Percentage (%)</SelectItem>
                    <SelectItem value="FixedAmount">
                      Fixed Amount ($)
                    </SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="discountValue">
                  Value {formData.discountType === "Percentage" ? "(%)" : "($)"}{" "}
                  *
                </Label>
                <Input
                  id="discountValue"
                  type="number"
                  min="0"
                  step="0.01"
                  placeholder={
                    formData.discountType === "Percentage" ? "20" : "10.00"
                  }
                  disabled={isPending}
                  className={errors.discountValue ? "border-destructive" : ""}
                  {...field("discountValue")}
                />
                {errors.discountValue && (
                  <p className="text-sm text-destructive">
                    {errors.discountValue}
                  </p>
                )}
              </div>
            </div>

            {/* Valid From + Valid Until */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label htmlFor="validFrom">Valid From *</Label>
                <Input
                  id="validFrom"
                  type="date"
                  disabled={isPending}
                  className={errors.validFrom ? "border-destructive" : ""}
                  {...field("validFrom")}
                />
                {errors.validFrom && (
                  <p className="text-sm text-destructive">{errors.validFrom}</p>
                )}
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="validUntil">Valid Until</Label>
                <Input
                  id="validUntil"
                  type="date"
                  disabled={isPending}
                  {...field("validUntil")}
                />
              </div>
            </div>

            {/* Optional constraints */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label htmlFor="minOrderAmount">Min Order Amount ($)</Label>
                <Input
                  id="minOrderAmount"
                  type="number"
                  min="0"
                  step="0.01"
                  placeholder="50.00"
                  disabled={isPending}
                  {...field("minOrderAmount")}
                />
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="maxDiscountAmount">Max Discount ($)</Label>
                <Input
                  id="maxDiscountAmount"
                  type="number"
                  min="0"
                  step="0.01"
                  placeholder="100.00"
                  disabled={isPending}
                  {...field("maxDiscountAmount")}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label htmlFor="usageLimit">Total Usage Limit</Label>
                <Input
                  id="usageLimit"
                  type="number"
                  min="1"
                  placeholder="100"
                  disabled={isPending}
                  {...field("usageLimit")}
                />
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="usagePerUser">Per-User Limit</Label>
                <Input
                  id="usagePerUser"
                  type="number"
                  min="1"
                  placeholder="1"
                  disabled={isPending}
                  {...field("usagePerUser")}
                />
              </div>
            </div>
          </div>

          <DialogFooter>
            <Button
              type="button"
              variant="outline"
              onClick={onClose}
              disabled={isPending}
            >
              Cancel
            </Button>
            <Button type="submit" disabled={isPending}>
              {isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {isEditing ? "Update" : "Create"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

